import{_ as s,c as a,o as e,a as n}from"./app.2dc46da8.js";const l='{"title":"Note","description":"","frontmatter":{},"headers":[{"level":2,"title":"CSS Properties","slug":"css-properties"},{"level":2,"title":"CSS Variable","slug":"css-variable"},{"level":3,"title":"Syntax","slug":"syntax"},{"level":3,"title":"Scopes in CSS Variable","slug":"scopes-in-css-variable"},{"level":2,"title":"Position","slug":"position"},{"level":3,"title":"top, bottom, left, and right","slug":"top-bottom-left-and-right"},{"level":3,"title":"static","slug":"static"},{"level":3,"title":"relative","slug":"relative"},{"level":3,"title":"absolute","slug":"absolute"},{"level":3,"title":"inherit","slug":"inherit"}],"relativePath":"docs/css/CSS2.md"}',o={},t=[n('<h1 id="note" tabindex="-1">Note <a class="header-anchor" href="#note" aria-hidden="true">#</a></h1><h2 id="css-properties" tabindex="-1">CSS Properties <a class="header-anchor" href="#css-properties" aria-hidden="true">#</a></h2><p>::before 选择器向选定的<strong>元素</strong>前插入内容</p><p>hsl() 函数使用色相、饱和度、亮度来定义颜色。</p><p>HSL 即色相、饱和度、亮度（英语：Hue, Saturation, Lightness）。</p><ul><li>**色相（H）**是色彩的基本属性，就是平常所说的颜色名称，如红色、黄色等。</li><li>**饱和度（S）**是指色彩的纯度，越高色彩越纯，低则逐渐变灰，取 0-100% 的数值。</li><li><strong>亮度（L）</strong>，取 0-100%，增加亮度，颜色会向白色变化；减少亮度，颜色会向黑色变化。</li></ul><p>HSL 是一种将 RGB 色彩模型中的点在圆柱坐标系中的表示法。这两种表示法试图做到比基于笛卡尔坐标系的几何结构 RGB 更加直观。</p><p>CSS overflow 属性可以控制内容溢出元素框时在对应的元素区间内添加滚动条</p><p><img src="/assets/image-20220511194221503.11e0164f.png" alt=""></p><h2 id="css-variable" tabindex="-1">CSS Variable <a class="header-anchor" href="#css-variable" aria-hidden="true">#</a></h2><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-hidden="true">#</a></h3><h4 id="declaring-a-css-variable" tabindex="-1">Declaring a CSS variable <a class="header-anchor" href="#declaring-a-css-variable" aria-hidden="true">#</a></h4><div class="language-css"><pre><code><span class="line"><span style="color:#A6ACCD;">--variable-name: </span><span style="color:#FFCB6B;">some-value</span><span style="color:#A6ACCD;">;</span></span>\n<span class="line"></span></code></pre></div><h4 id="using-the-css-variable" tabindex="-1">Using the CSS variable <a class="header-anchor" href="#using-the-css-variable" aria-hidden="true">#</a></h4><div class="language-css"><pre><code><span class="line"><span style="color:#FFCB6B;">css-property</span><span style="color:#A6ACCD;">: var(--variable-name);</span></span>\n<span class="line"></span></code></pre></div><h3 id="scopes-in-css-variable" tabindex="-1">Scopes in CSS Variable <a class="header-anchor" href="#scopes-in-css-variable" aria-hidden="true">#</a></h3><h4 id="global-scope" tabindex="-1">Global Scope <a class="header-anchor" href="#global-scope" aria-hidden="true">#</a></h4><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">:</span><span style="color:#C792EA;">root</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  --primary-color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">#</span><span style="color:#A6ACCD;">000</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#FFCB6B;">h1</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">var</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">--primary-color</span><span style="color:#89DDFF;">);</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><h2 id="position" tabindex="-1">Position <a class="header-anchor" href="#position" aria-hidden="true">#</a></h2><h3 id="top-bottom-left-and-right" tabindex="-1"><code>top</code>, <code>bottom</code>, <code>left</code>, and <code>right</code> <a class="header-anchor" href="#top-bottom-left-and-right" aria-hidden="true">#</a></h3><p><strong>元素通常会在其值为正时远离给定的一侧，而在值为负时朝它移动。</strong></p><p>下图是在调整<code>top</code></p><p><img src="/assets/image-20220529214833594.0b0a7c38.png" alt=""></p><h3 id="static" tabindex="-1">static <a class="header-anchor" href="#static" aria-hidden="true">#</a></h3><p>Every element has a static position by default</p><p>So if there is a <a href="https://css-tricks.com/almanac/properties/l/left/" target="_blank" rel="noopener noreferrer">left</a>/<a href="https://css-tricks.com/almanac/properties/r/right/" target="_blank" rel="noopener noreferrer">right</a>/<a href="https://css-tricks.com/almanac/properties/t/top/" target="_blank" rel="noopener noreferrer">top</a>/<a href="https://css-tricks.com/almanac/properties/b/bottom/" target="_blank" rel="noopener noreferrer">bottom</a>/<a href="https://css-tricks.com/almanac/properties/z/z-index/" target="_blank" rel="noopener noreferrer">z-index</a> set then there will be <strong>no effect on</strong> that element.</p><h3 id="relative" tabindex="-1">relative <a class="header-anchor" href="#relative" aria-hidden="true">#</a></h3><p>An element’s original position remains in the flow of the document, just like the <code>static</code> value.</p><p>But now <a href="https://css-tricks.com/almanac/properties/l/left/" target="_blank" rel="noopener noreferrer">left</a>/<a href="https://css-tricks.com/almanac/properties/r/right/" target="_blank" rel="noopener noreferrer">right</a>/<a href="https://css-tricks.com/almanac/properties/t/top/" target="_blank" rel="noopener noreferrer">top</a>/<a href="https://css-tricks.com/almanac/properties/b/bottom/" target="_blank" rel="noopener noreferrer">bottom</a>/<a href="https://css-tricks.com/almanac/properties/z/z-index/" target="_blank" rel="noopener noreferrer">z-index</a> <strong>will work</strong>.</p><h3 id="absolute" tabindex="-1">absolute <a class="header-anchor" href="#absolute" aria-hidden="true">#</a></h3><p>The element is removed from the flow of the document and other elements will behave as if it’s not even there whilst all the other positional properties will work on it.</p><p>If a child element has an <code>absolute</code> value then the parent element will behave as if the child isn’t there at all.</p><p>when we try to set other values such as <code>left</code>, <code>bottom</code>, and <code>right</code> we’ll find that the child element is responding not to the dimensions of its parent, but <strong>the document</strong></p><blockquote><p>属性为absolute的元素在设定left,bottom,right等时是以整个document作为参照</p></blockquote><p>如果要使子元素相对于其父元素绝对定位的话，需要在父元素上设置<code>relative</code>的属性</p><div class="language-css"><pre><code><span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">parent</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">position</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> relative</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">element</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">background-color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">rgba</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#F78C6C;">.3</span><span style="color:#89DDFF;">);</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">padding</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">20px</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">color</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">rgba</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">255</span><span style="color:#89DDFF;">,</span><span style="color:#F78C6C;">255</span><span style="color:#89DDFF;">,</span><span style="color:#F78C6C;">255</span><span style="color:#89DDFF;">,</span><span style="color:#F78C6C;">.4</span><span style="color:#89DDFF;">);</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">position</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> absolute</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">bottom</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">left</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#B2CCD6;">right</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">;</span></span>\n<span class="line"><span style="color:#89DDFF;">}</span></span>\n<span class="line"></span></code></pre></div><h3 id="inherit" tabindex="-1">inherit <a class="header-anchor" href="#inherit" aria-hidden="true">#</a></h3><p>The <code>position</code> value doesn’t cascade, so this can be used to specifically force it to, and <code>inherit</code> the positioning value from its parent.</p>',38)];var r=s(o,[["render",function(s,n,l,o,r,p){return e(),a("div",null,t)}]]);export{l as __pageData,r as default};
